member.remarks:
This method enables LINQ query syntax for Option types. It is an alias for the Map method
and allows writing queries like:

var result = from x in GetOption()
             select x * 2;

This overload enables full LINQ query syntax support including multiple from clauses
with projections:

var result = from x in GetX()
             from y in GetY(x)
             select x + y;

This method enables where clauses in LINQ queries and is an alias for the Filter method:

var result = from x in GetOption()
             where x > 0
             select x;

member.returns:
A result containing Some if the original result was successful with a non-null value; 
            a result containing None if the original result was successful with a null value; 
            or a failed result if the original result was failed.

A result containing Some if the original result was successful with a value; 
            a result containing None if the original result was successful with null; 
            or a failed result if the original result was failed.

example.code:
var errors = new List<Error>
{
    new ValidationError("User.InvalidEmail", "Email format is invalid"),
    new ValidationError("User.PasswordTooShort", "Password must be at least 8 characters"),
    new ValidationError("User.UsernameTaken", "Username already exists")
};

var aggregateError = new AggregateError(errors);
// Returns a Result<T> with all validation errors combined

// Simple authentication error
var error = new AuthenticationError("Auth.InvalidCredentials", "Invalid username or password");

// Authentication error with metadata
var metadata = new Dictionary<string, object>
{
    ["Username"] = username,
    ["AuthMethod"] = "password",
    ["FailedAttempts"] = 3,
    ["LastAttempt"] = DateTime.UtcNow
};
var detailedError = new AuthenticationError("Auth.InvalidCredentials", 
    "Invalid username or password", metadata);

// Used in an authentication service
public Result<AuthToken> Authenticate(string username, string password)
{
    var user = userRepository.FindByUsername(username);
    if (user == null || !VerifyPassword(password, user.PasswordHash))
        return new AuthenticationError("Auth.InvalidCredentials", "Invalid username or password");

    return GenerateToken(user);
}

// Token validation
public Result<ClaimsPrincipal> ValidateToken(string token)
{
    if (IsTokenExpired(token))
        return new AuthenticationError("Auth.TokenExpired", "Authentication token has expired");

    if (!IsTokenValid(token))
        return new AuthenticationError("Auth.InvalidToken", "Authentication token is invalid");

    return ExtractClaims(token);
}

// Simple authorization error
var error = new AuthorizationError("Auth.InsufficientPermissions", "User lacks admin privileges");

// Authorization error with metadata
var metadata = new Dictionary<string, object>
{
    ["RequiredRole"] = "Admin",
    ["UserRole"] = "Member",
    ["Resource"] = "UserManagement",
    ["Action"] = "Delete"
};
var detailedError = new AuthorizationError("Auth.RoleRequired", 
    "Admin role required to delete users", metadata);

// Used in an authorization service
public Result<T> AuthorizeAction<T>(User user, string resource, string action, Func<Result<T>> operation)
{
    if (!HasPermission(user, resource, action))
    {
        var metadata = new Dictionary<string, object>
        {
            ["UserId"] = user.Id,
            ["Resource"] = resource,
            ["Action"] = action
        };
        return new AuthorizationError("Auth.AccessDenied", 
            $"Access denied to {action} {resource}", metadata);
    }

    return operation();
}

// Resource-based authorization
public Result<Document> GetDocument(User user, int documentId)
{
    var document = documentRepository.FindById(documentId);
    if (document == null)
        return new NotFoundError("Document.NotFound", $"Document {documentId} not found");

    if (document.OwnerId != user.Id && !user.IsAdmin)
        return new AuthorizationError("Auth.ResourceAccessDenied", 
            "You don't have permission to access this document");

    return document;
}

// Simple conflict error
var error = new ConflictError("User.DuplicateEmail", "A user with this email already exists");

// Conflict error with metadata
var metadata = new Dictionary<string, object>
{
    ["Email"] = email,
    ["ExistingUserId"] = existingUserId,
    ["AttemptedOperation"] = "CreateUser"
};
var detailedError = new ConflictError("User.DuplicateEmail", 
    $"Cannot create user: email '{email}' is already in use", metadata);

// Optimistic concurrency conflict
public Result<Order> UpdateOrder(Order order, int expectedVersion)
{
    var currentVersion = database.GetOrderVersion(order.Id);
    if (currentVersion != expectedVersion)
    {
        var metadata = new Dictionary<string, object>
        {
            ["OrderId"] = order.Id,
            ["ExpectedVersion"] = expectedVersion,
            ["CurrentVersion"] = currentVersion
        };
        return new ConflictError("Order.VersionConflict", 
            "Order has been modified by another user", metadata);
    }

    return database.UpdateOrder(order);
}

// Business state conflict
public Result CancelOrder(int orderId)
{
    var order = database.GetOrder(orderId);
    if (order.Status == OrderStatus.Shipped)
    {
        return new ConflictError("Order.CannotCancel", 
            "Cannot cancel order that has already been shipped");
    }

    return database.CancelOrder(orderId);
}

// Simple not found error
var error = new NotFoundError("User.NotFound", "User with ID '123' was not found");

// Not found error with metadata
var metadata = new Dictionary<string, object>
{
    ["UserId"] = userId,
    ["SearchCriteria"] = "ID",
    ["Timestamp"] = DateTime.UtcNow
};
var detailedError = new NotFoundError("User.NotFound", $"User with ID '{userId}' was not found", metadata);

// Used in a repository method
public Result<User> GetUserById(int userId)
{
    var user = database.Users.FindById(userId);
    if (user == null)
        return new NotFoundError("User.NotFound", $"User with ID '{userId}' was not found");

    return user;
}

// Used in a file service
public Result<string> ReadFile(string path)
{
    if (!File.Exists(path))
        return new NotFoundError("File.NotFound", $"File '{path}' does not exist");

    return File.ReadAllText(path);
}

// Simple validation error
var error = new ValidationError("User.InvalidEmail", "Email format is invalid");

// Validation error with metadata
var metadata = new Dictionary<string, object>
{
    ["Field"] = "email",
    ["Value"] = "invalid-email",
    ["Pattern"] = @"^[\w-\.]+@([\w-]+\.)+[\w-]{2,4}$"
};
var detailedError = new ValidationError("User.InvalidEmail", "Email format is invalid", metadata);

// Used in a validation method
public static Result<string> ValidateEmail(string email)
{
    if (!IsValidEmail(email))
        return new ValidationError("User.InvalidEmail", $"'{email}' is not a valid email address");

    return email;
}

var validations = new[] { 
    ValidateField1(), 
    ValidateField2(), 
    ValidateField3() 
};
var result = validations.CollectAll(); // Collects all validation errors

var results = ProcessBatch(items);
var (successCount, errors) = results.Partition();
Console.WriteLine($"Processed {successCount} items successfully");
Console.WriteLine($"Failed to process {errors.Count()} items");

var permissionCheck = CheckPermissions();
var quotaCheck = CheckQuota();
var combined = permissionCheck.Combine(quotaCheck);

member.remarks:
This overload enables full LINQ query syntax with select clauses.
Since unit results have no value, the resultSelector takes no parameters.

var result = from _ in ValidatePermissions()
             from __ in CheckQuota()
             select "Operations completed successfully";

This overload is useful when you need to transition from a unit result to a value result
and then transform that value:

var result = from _ in ValidateInput()
             from data in LoadData()
             select data.Transform();

This method enables where clauses in LINQ queries for unit results:

var result = from _ in CheckPermissions()
             where IsBusinessHours()
             from __ in PerformOperation()
             select Unit.Value;

Note: The error parameter is not available in LINQ query syntax and will use a default error.

example.code:
var results = new[] { 
    Result.Failure<int>(error1), 
    Result.Success(2), 
    Result.Failure<int>(error2) 
};
var collected = results.CollectAll(); // Failure with AggregateError containing [error1, error2]

var results = GetResults();
var (successes, failures) = results.Partition();
Console.WriteLine($"Processed {successes.Count()} items successfully");
Console.WriteLine($"Failed to process {failures.Count()} items");

member.remarks:
This method enables LINQ query syntax for Result types. It is an alias for the Map method
and allows writing queries like:

var result = from x in GetResult()
             select x * 2;

This overload enables full LINQ query syntax support including multiple from clauses
with projections:

var result = from x in GetX()
             from y in GetY(x)
             select x + y;

This method enables where clauses in LINQ queries:

var result = from x in GetResult()
             where x > 0
             select x;

Note: The error parameter is not available in LINQ query syntax and will use a default error.

This class contains static factory members and methods that create ValidationError instances
for numeric validation failures. These errors support validation of numeric ranges, signs,
and specific numeric values across all numeric types (int, long, double, decimal, etc.).

This converter serializes results as objects with the following structure:
- For success: { "isSuccess": true, "value": ... }
- For failure: { "isSuccess": false, "error": ... }
